ts-error-handling.reference_solution:
type Command = { kind: "add"; left: number; right: number } | { kind: "divide"; left: number; right: number };
function parseNumber(token: string | undefined): number {
  if (token === undefined || token.trim() === "") throw new Error("missing number");
  const value = Number(token);
  if (!Number.isFinite(value)) throw new Error("invalid number");
  return value;
}
function parse(input: string): Command {
  const [kind, leftText, rightText] = input.split(/\s+/);
  if (kind !== "add" && kind !== "divide") throw new Error("invalid command");
  const left = parseNumber(leftText);
  const right = parseNumber(rightText);
  if (kind === "divide") {
    if (right === 0) throw new Error("division by zero");
    return { kind, left, right };
  }
  return { kind: "add", left, right };
}
async function execute(command: Command): Promise<number> {
  switch (command.kind) {
    case "add": return command.left + command.right;
    case "divide": return command.left / command.right;
    default: { const exhaustive: never = command; return exhaustive; }
  }
}
function failureLabel(error: unknown): string { return error instanceof Error ? "invalid" : "unknown"; }
async function main(): Promise<void> {
  const raw = require("node:fs").readFileSync(0, "utf8").trim();
  process.stdout.write(`${await execute(parse(raw))}\n`);
}
main().catch((error: unknown) => process.stdout.write(`${failureLabel(error)}\n`));
